using System.IO.Abstractions;

namespace MyApp.Services;

public interface IFileSystemWrapper
{
    // File operations
    string ReadAllText(string path);
    byte[] ReadAllBytes(string path);
    string[] ReadAllLines(string path);
    void WriteAllText(string path, string contents);
    void WriteAllBytes(string path, byte[] bytes);
    void WriteAllLines(string path, string[] contents);
    Stream OpenRead(string path);
    Stream Create(string path);
    void CopyFile(string sourceFileName, string destFileName, bool overwrite = false);
    void MoveFile(string sourceFileName, string destFileName, bool overwrite = false);
    void DeleteFile(string path);
    bool FileExists(string path);

    // Directory operations
    IDirectoryInfo CreateDirectory(string path);
    void DeleteDirectory(string path, bool recursive = false);
    bool DirectoryExists(string path);
    string[] GetFiles(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly);
    string[] GetDirectories(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly);

    // Path operations
    string Combine(params string[] paths);
    string GetDirectoryName(string path);
    string GetFileName(string path);
    string GetFileNameWithoutExtension(string path);
    string GetExtension(string path);
    string GetFullPath(string path);
    string GetTempPath();
}

public class FileSystemWrapper(IFileSystem fileSystem) : IFileSystemWrapper
{
    // File operations
    public string ReadAllText(string path) => fileSystem.File.ReadAllText(path);
    public byte[] ReadAllBytes(string path) => fileSystem.File.ReadAllBytes(path);
    public string[] ReadAllLines(string path) => fileSystem.File.ReadAllLines(path);
    public void WriteAllText(string path, string contents) => fileSystem.File.WriteAllText(path, contents);
    public void WriteAllBytes(string path, byte[] bytes) => fileSystem.File.WriteAllBytes(path, bytes);
    public void WriteAllLines(string path, string[] contents) => fileSystem.File.WriteAllLines(path, contents);
    public Stream OpenRead(string path) => fileSystem.File.OpenRead(path);
    public Stream Create(string path) => fileSystem.File.Create(path);
    public void CopyFile(string sourceFileName, string destFileName, bool overwrite = false) =>
        fileSystem.File.Copy(sourceFileName, destFileName, overwrite);
    public void MoveFile(string sourceFileName, string destFileName, bool overwrite = false) =>
        fileSystem.File.Move(sourceFileName, destFileName, overwrite);
    public void DeleteFile(string path) => fileSystem.File.Delete(path);
    public bool FileExists(string path) => fileSystem.File.Exists(path);

    // Directory operations
    public IDirectoryInfo CreateDirectory(string path) => fileSystem.Directory.CreateDirectory(path);
    public void DeleteDirectory(string path, bool recursive = false) => fileSystem.Directory.Delete(path, recursive);
    public bool DirectoryExists(string path) => fileSystem.Directory.Exists(path);
    public string[] GetFiles(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly) =>
        fileSystem.Directory.GetFiles(path, searchPattern, searchOption);
    public string[] GetDirectories(string path, string searchPattern = "*", SearchOption searchOption = SearchOption.TopDirectoryOnly) =>
        fileSystem.Directory.GetDirectories(path, searchPattern, searchOption);

    // Path operations
    public string Combine(params string[] paths) => fileSystem.Path.Combine(paths);
    public string GetDirectoryName(string path) => fileSystem.Path.GetDirectoryName(path)!;
    public string GetFileName(string path) => fileSystem.Path.GetFileName(path);
    public string GetFileNameWithoutExtension(string path) => fileSystem.Path.GetFileNameWithoutExtension(path);
    public string GetExtension(string path) => fileSystem.Path.GetExtension(path);
    public string GetFullPath(string path) => fileSystem.Path.GetFullPath(path);
    public string GetTempPath() => fileSystem.Path.GetTempPath();
}

